sql:
SELECT COUNT(DISTINCT university_id) AS total_universities
FROM rankings
WHERE rank_type = 'global';

external_knowledge:
- 'Balanced student-to-staff ratio' refers to a ratio between 5 and 7;
- 'Shining star' refers to the university with the highest average overall score;
- 'Times Higher Education' is a recognized source for university rankings.

